 1	import React, { FC } from 'react';
 2	
 3	import { V1Template } from '@kubevirt-ui/kubevirt-api/console';
 4	import { logTemplateFlowEvent } from '@kubevirt-utils/extensions/telemetry/telemetry';
 5	import { CANCEL_CREATE_VM_BUTTON_CLICKED } from '@kubevirt-utils/extensions/telemetry/utils/constants';
 6	import { getTemplateName } from '@kubevirt-utils/resources/template/utils/selectors';
 7	import { CatalogItemHeader } from '@patternfly/react-catalog-view-extension';
 8	import { Modal } from '@patternfly/react-core';
 9	
10	import { getTemplateOSIcon } from '../../utils/os-icons';
11	
12	import { DrawerContextProvider } from './hooks/useDrawerContext';
13	import { TemplatesCatalogDrawerFooter } from './TemplatesCatalogDrawerFooter';
14	import { TemplatesCatalogDrawerPanel } from './TemplatesCatalogDrawerPanel';
15	
16	import './TemplateCatalogDrawer.scss';
17	
18	type TemplatesCatalogDrawerProps = {
19	  isOpen: boolean;
20	  namespace: string;
21	  onClose: () => void;
22	  template: undefined | V1Template;
23	};
24	
25	export const TemplatesCatalogDrawer: FC<TemplatesCatalogDrawerProps> = ({
26	  isOpen,
27	  namespace,
28	  onClose,
29	  template,
30	}) => {
31	  const templateName = getTemplateName(template);
32	  const osIcon = getTemplateOSIcon(template);
33	
34	  if (!isOpen) return null;
35	
36	  const handleCancel = () => {
37	    logTemplateFlowEvent(CANCEL_CREATE_VM_BUTTON_CLICKED, template);
38	    onClose();
39	  };
40	
41	  return (
42	    <DrawerContextProvider template={template}>
43	      <Modal
44	        footer={
45	          template && <TemplatesCatalogDrawerFooter namespace={namespace} onCancel={handleCancel} />
46	        }
47	        header={
48	          <CatalogItemHeader
49	            className="co-catalog-page__overlay-header"
50	            iconImg={osIcon}
51	            title={templateName}
52	            vendor={template?.metadata?.name}
53	          />
54	        }
55	        aria-label="Template drawer"
56	        className="pf-v6-c-modal-box ocs-modal co-catalog-page__overlay co-catalog-page__overlay--right template-catalog-drawer"
57	        disableFocusTrap
58	        isOpen={isOpen}
59	        onClose={onClose}
60	      >
61	        <TemplatesCatalogDrawerPanel />
62	      </Modal>
63	    </DrawerContextProvider>
64	  );
65	};

